async def validate_token(
    credentials: HTTPAuthorizationCredentials = Security(security_scheme),
    redis_client: redis.Redis = Depends(get_redis),
) -> TokenData:
    """
    Dependency that validates OAuth 2.0 bearer tokens by checking Redis cache.
    Extracts the token from the Authorization header and looks it up in Redis.
    """
    token = credentials.credentials

    if not token or len(token) < 10:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid token format",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    redis_key = f"{TOKEN_PREFIX}{token}"

    try:
        token_json = await redis_client.get(redis_key)
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Token store unavailable: {str(e)}",
        )

    if token_json is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token not found or expired",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    try:
        token_data_dict = json.loads(token_json)
        token_data = TokenData(**token_data_dict)
    except (json.JSONDecodeError, ValueError) as e:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail=f"Corrupted token data: {str(e)}",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    expires_at = datetime.fromisoformat(token_data.expires_at)
    if datetime.utcnow() > expires_at:
        await redis_client.delete(redis_key)
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Token has expired",
            headers={"WWW-Authenticate": "Bearer error=\"invalid_token\""},
        )

    return token_data


def require_scopes(*required_scopes: str):
    """
    Factory function that creates a dependency requiring specific OAuth scopes.
    """
    async def scope_validator(
        token_data: TokenData = Depends(validate_token),
    ) -> TokenData:
        for scope in required_scopes:
            if scope not in token_data.scopes:
                raise HTTPException(
                    status_code=status.HTTP_403_FORBIDDEN,
                    detail=f"Insufficient scope. Required: {required_scopes}, "
                           f"granted: {token_data.scopes}",
                    headers={
                        "WWW-Authenticate": f"Bearer error=\"insufficient_scope\", "
                                            f"scope=\"{' '.join(required_scopes)}\""
                    },
                )
        return token_data

    return scope_validator


@app.get("/health", response_model=HealthResponse, tags=["Health"])
async def health_check():
    """Health check endpoint - no authentication required."""
    redis_connected = False
    if redis_pool:
        try:
            await redis_pool.ping()
            redis_connected = True
        except Exception:
            pass

    return HealthResponse(
        status="healthy" if redis_connected else "degraded",
        redis_connected=redis_connected,
        timestamp=datetime.utcnow().isoformat(),
    )


@app.post("/auth/token", response_model=TokenResponse, tags=["Authentication"])
async def create_token(
    user_id: str,
    client_id: str = "default_client",
    scopes: str = "read",
    redis_client: redis.Redis = Depends(get_redis),
):
    """
    Create a new OAuth 2.0 token and store it in Redis.
    In production, this would be handled by a proper OAuth 2.0 authorization server.
    This endpoint is for demonstration/testing purposes.
    """
    access_token = secrets.token_urlsafe(48)
    scope_list = [s.strip() for s in scopes.split(",")]

    now = datetime.utcnow()
    expires_at = now + timedelta(seconds=TOKEN_EXPIRY_SECONDS)

    token_data = TokenData(
        user_id=user_id,
        scopes=scope_list,
        client_id=client_id,
        issued_at=now.isoformat(),
        expires_at=expires_at.isoformat(),
    )

    redis_key = f"{TOKEN_PREFIX}{access_token}"

    try:
        await redis_client.setex(
            redis_key,
            TOKEN_EXPIRY_SECONDS,
            token_data.model_dump_json(),
        )
    except redis.RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail=f"Failed to store token: {str(e)}",
        )

    return TokenResponse(
        access_token=access_token,
        expires_in=TOKEN_EXPIRY_SECONDS,
        user_id=user_id,
        scopes=scope_list,
    )


